package main

import (
    "fmt"
    "time"
)

func main() {
    now := time.Now()
    fmt.Println("Current:", now.Format("2006-01-02 15:04:05"))

    // Parsing
    t, _ := time.Parse("2006-01-02", "2024-12-25")
    fmt.Println("Christmas:", t)

    // Duration
    dur := time.Until(t)
    fmt.Printf("Days until Christmas: %.0f\n", dur.Hours()/24)

    // Timer
    fmt.Println("Waiting 100ms...")
    timer := time.NewTimer(100 * time.Millisecond)
    <-timer.C
    fmt.Println("Done!")
}
